def generate_narration_scripts(headlines_by_genre):
    '''
    Generates a news-anchor-style narration script for each genre, summarizing the latest headlines.
    Args:
        headlines_by_genre (dict): Genre as key, list of headline strings as value.
    Returns:
        dict: Genre as key, news-anchor-style script as value.
    '''
    import datetime
    scripts = {}
    timestamp = datetime.datetime.now().isoformat()
    for genre, headlines in headlines_by_genre.items():
        script = f"Here’s your quick update on {genre}… "
        if headlines:
            script += ' '.join([f"Headline: {h}" for h in headlines])
        else:
            script += "No new headlines available at this time."
        scripts[genre] = {"timestamp": timestamp, "script": script}
    return scripts
